const today = new Date().toISOString().slice(0, 10);
const now = new Date();
const weekNumber = Math.ceil((((now - new Date(now.getFullYear(), 0, 1)) / 86400000) + new Date(now.getFullYear(), 0, 1).getDay() + 1) / 7);
const date = `${String(now.getDate()).padStart(2,'0')}/${String(now.getMonth()+1).padStart(2,'0')}/${now.getFullYear()}`;

const done = $('Tasks Concluidas').all().map(i => {
  const name = i.json.property_name || 'Sem nome';
  const tags = i.json.property_tags || [];
  return `${name}${tags.length ? ' [' + tags.join(', ') + ']' : ''}`;
}).join('\n');
const doneCount = $('Tasks Concluidas').all().length;

const overdue = $('Tasks Atrasadas').all().map(i => {
  const name = i.json.property_name || 'Sem nome';
  const due = i.json.property_due_date?.start || '';
  const tags = i.json.property_tags || [];
  const prio = tags.includes('Prioridade Alta') ? 'ALTA' : tags.includes('Prioridade Media') ? 'MEDIA' : '';
  return `${prio ? prio + ' ' : ''}${name} (due: ${due})${tags.length ? ' [' + tags.join(', ') + ']' : ''}`;
}).join('\n');
const overdueCount = $('Tasks Atrasadas').all().length;

const createdCount = $('Tasks Criadas Semana').all().length;

const projects = $('Active Projects').all().map(i => {
  const name = i.json.property_name || i.json.Name || 'Sem nome';
  const type = i.json.property_type || '';
  return `${name}${type ? ' (' + type + ')' : ''}`;
}).join('\n');

const memoryContext = $('Memory Read').first().json.memoryContext || 'Nenhuma memoria recente.';

const prompt = `Hoje e ${date}, sexta-feira. SWOT Semanal para Ary Ribeiro.

${memoryContext}

CONTEXTO: Consultor IA, 3 verticais: TJ (advogados BR R$2.997/mes), TM (clinicas BR R$2.997/mes), CL (imobiliarias PT E497/mes). Meta Q2: E12.857 trimestral (~E4.286/mes). Revenue actual: E0. Pipeline vazio = crise.

PROJECTOS ACTIVOS (${$('Active Projects').all().length}):
${projects || '(nenhum projecto activo)'}

TASKS CONCLUIDAS ESTA SEMANA (${doneCount}):
${done || '(nenhuma task concluida - semana perdida)'}

TASKS ATRASADAS (${overdueCount}):
${overdue || '(nenhuma task atrasada)'}

VOLUME: ${createdCount} tasks criadas esta semana

ANALISA estes dados e gera um SWOT estrategico:

REGRAS:
1. STRENGTHS: baseado APENAS em tasks concluidas (wins reais)
2. WEAKNESSES: tasks atrasadas + projectos sem actividade + revenue E0
3. OPPORTUNITIES: padroes detectados + o que acelerar na proxima semana para gerar receita
4. THREATS: atrasos acumulados + pipeline vazio + riscos de nao atingir meta Q2
5. Se revenue = E0 e pipeline vazio, THREATS deve incluir risco existencial de nao gerar caixa
6. Termina com 1 DECISAO ESTRATEGICA para a proxima semana (focada em revenue)
7. Brutalmente honesto - zero fluff, tom de board member exigente
8. Se nao ha dados suficientes para uma categoria, diz dados insuficientes
9. Se a memoria recente contem decisoes ou padroes relevantes, INCORPORA na analise SWOT

FORMATO:
SWOT Semanal - Semana ${weekNumber}/2026

STRENGTHS
- [wins da semana]

WEAKNESSES
- [gaps e falhas]

OPPORTUNITIES
- [o que acelerar + revenue opportunities]

THREATS
- [riscos acumulados + pipeline status]

PROJECTOS
- [status dos activos com flags]

MEMORIA
- [1-2 bullets de padroes ou decisoes de sessoes anteriores que impactam esta analise]

DECISAO #1 PROXIMA SEMANA
[1 frase imperativa focada em revenue]

Maximo 400 palavras.`;

return [{ json: { prompt, timeout: 120000 } }];

const output = $('Claude Bridge').item.json.output;
const elapsed = $('Claude Bridge').item.json.elapsed_s;
const now = new Date();
const date = `${String(now.getDate()).padStart(2,'0')}/${String(now.getMonth()+1).padStart(2,'0')}/${now.getFullYear()}`;

let text = output
  .replace(/\*\*(.*?)\*\*/g, '*$1*')
  .replace(/^- /gm, '• ')
  .replace(/---/g, '───');

text = `📊 SWOT Semanal — ${date}\n\n${text}\n\n───\n⏱️ Gerado em ${elapsed}s via Claude Code (with memory)`;

if (text.length > 4000) {
  text = text.substring(0, 3950) + '\n\n(truncado)';
}

return [{ json: { text, number: '351913095597' } }];

const bridgeOutput = $input.first().json;

if (bridgeOutput.output && bridgeOutput.output.length > 10) {
  return [{ json: { output: bridgeOutput.output, elapsed_s: bridgeOutput.elapsed_s || 0, fallback: false, prompt: '' } }];
}

const prompt = $('Build SWOT Prompt + Memory').first().json.prompt || '';
return [{ json: { output: '', elapsed_s: 0, fallback: true, prompt: prompt } }];

const response = $input.first().json;
const content = response.message?.content || 'Erro: Ollama nao respondeu';
return [{ json: { output: content + '\n\n⚠️ Gerado via Gemma3:27b (fallback local)', elapsed_s: 0 } }];
